const fs = require('fs');
const zlib = require('zlib');
const path = require('path');

const filePath = 'C:\\Users\\yyzypublic\\Downloads\\__APP__.wxapkg';
const b = fs.readFileSync(filePath);

console.log('File size:', b.length);

// Check magic
const magic = b.slice(0, 6).toString();
console.log('Magic:', magic, JSON.stringify(magic));

// Check info bytes after magic
console.log('Bytes 6-20 hex:', b.slice(6, 20).toString('hex'));

// Try to find valid compressed data by XORing with first few bytes
// PC wxapkg format: magic(6 bytes) + info + XOR-encrypted zlib data
// The XOR key is often the first few bytes of the file or based on file name

// Method 1: Try XOR with magic bytes
function tryXor(buf, key) {
  const result = Buffer.alloc(buf.length);
  for (let i = 0; i < buf.length; i++) {
    result[i] = buf[i] ^ key[i % key.length];
  }
  return result;
}

// Try with 'V1MMWX'
const key1 = Buffer.from('V1MMWX');
const dec1 = tryXor(b, key1);
console.log('\nXOR with V1MMWX, checking for zlib at various offsets:');
for (let o = 0; o < Math.min(500, b.length - 2); o++) {
  if ((dec1[o] === 0x78 && (dec1[o+1] === 0x01 || dec1[o+1] === 0x5e || dec1[o+1] === 0x9c || dec1[o+1] === 0xda))) {
    console.log('  zlib found at offset', o, 'hex:', dec1.slice(o, o+4).toString('hex'));
  }
  // Also check JSON-like patterns
  if (dec1[o] === 0x7b) { // '{'
    const snippet = dec1.slice(o, o+20).toString('utf8');
    if (snippet.startsWith('{') || snippet.startsWith('[')) {
      console.log('  potential JSON at', o, ':', snippet);
    }
  }
}

// Look for file entries - in wxapkg format, there's usually a table of contents
// Try reading as a structured index
// Standard wxapkg format (some versions):
// Header: magic(1 byte) + info
// Index: list of (nameLen, name, offset, size) pairs
// Then file data

// Check if it might be a known structure
console.log('\nFile structure analysis:');
// Read as unsigned ints
const readU32 = (off) => b.readUInt32LE(off);
console.log('U32 at 0:', readU32(0).toString(16));
console.log('U32 at 4:', readU32(4).toString(16));
console.log('U32 at 8:', readU32(8).toString(16));
console.log('U32 at 12:', readU32(12).toString(16));
console.log('U32 at 16:', readU32(16).toString(16));
console.log('U32 at 20:', readU32(20).toString(16));

// Look for readable strings
let offsets = [];
for (let i = 0; i < b.length - 10; i += 4) {
  const v = readU32(i);
  if (v > 0 && v < b.length && (b[i+4] > 0 && b[i+4] < 200)) {
    // could be offset/size pair
    offsets.push({off: i, val: v});
  }
}

// Search for common file extensions
const searchStr = (str) => {
  const idx = b.indexOf(str);
  if (idx >= 0) console.log('  Found', JSON.stringify(str), 'at offset', idx);
};
['.js', '.json', '.html', '.wxss', '.wxml', '.png', '.jpg', '.svg', '.wxs', 'app.js', 'app.json', 'pages/', 'components/'].forEach(s => searchStr(s));

const fs = require('fs');
const zlib = require('zlib');

const filePath = 'C:\\Users\\yyzypublic\\Downloads\\__APP__.wxapkg';
const b = fs.readFileSync(filePath);

console.log('=== PC WeChat wxapkg Decrypt Attempt ===');
console.log('File size:', b.length);

// The magic for PC wxapkg is 'V1MMWX' (6 bytes)
const magic = b.slice(0, 6);
console.log('Magic:', magic.toString());

// Common approaches for PC wxapkg decryption:

// Approach 1: XOR all data after magic with the magic key
function tryDecrypt(buf, key) {
  const out = Buffer.alloc(buf.length);
  for (let i = 0; i < buf.length; i++) {
    out[i] = buf[i] ^ key[i % key.length];
  }
  return out;
}

// Approach 2: PC wxapkg sometimes uses XOR with shifted keys
// The encrypted data starts at offset 6
const encrypted = b.slice(6);

// Try different XOR keys
const keys = [
  'V1MMWX',
  'MMWX',
  'V1M',
  'WeChat',
  'wxapkg',
  Buffer.from([0x56, 0x31, 0x4d, 0x4d, 0x57, 0x58]) // V1MMWX
];

for (const key of keys) {
  const dec = tryDecrypt(encrypted, Buffer.isBuffer(key) ? key : Buffer.from(key));
  // Look for zlib magic 0x789c or 0x78da
  for (let o = 0; o < Math.min(1000, dec.length - 2); o++) {
    if ((dec[o] === 0x78 && (dec[o+1] === 0x9c || dec[o+1] === 0xda))) {
      console.log(`\nFound zlib at offset ${o} with key "${Buffer.isBuffer(key) ? key.toString() : key}"`);
      try {
        const decompressed = zlib.inflateSync(dec.slice(o));
        const text = decompressed.toString('utf8').substring(0, 500);
        console.log('Decompressed data preview:', text);
      } catch(e) {
        console.log('But inflate failed:', e.message);
      }
    }
  }
}

// Approach 3: Sometimes it's NOT XOR - it could be AES or just plain zlib
// Check if there's a zlib stream somewhere in the encrypted file
console.log('\nChecking for raw zlib in original data...');
for (let o = 0; o < Math.min(2000, b.length - 2); o++) {
  if ((b[o] === 0x78 && (b[o+1] === 0x9c || b[o+1] === 0xda))) {
    console.log(`Raw zlib at offset ${o}`);
    try {
      const decompressed = zlib.inflateSync(b.slice(o));
      const text = decompressed.toString('utf8').substring(0, 200);
      if (text.includes('{') || text.includes('app')) {
        console.log('Decompressed:', text);
      }
    } catch(e) {}
  }
}

// Approach 4: Some PC wxapkg use a simpler encryption
// The key idea: the first 1024 bytes are XOR encrypted with a rolling key
// Try reading the file directly as structured data
// Look for the "header" structure
console.log('\n=== Trying structured read ===');
// Some PC wxapkg have a simple structure:
// [magic][4-byte filecount][file records...][data...]
// Try reading as LE or BE integers
const readU32LE = (buf, off) => buf.readUInt32LE(off);
const readU32BE = (buf, off) => buf.readUInt32BE(off);

// The XOR key might be derived from the file path
// Path: __APP__.wxapkg
// Try different keys derived from the filename
const fileKeys = [
  '__APP__',
  '__APP__.wxapkg',
  'APP',
  'app',
  'WeChat',
  'wx',
  'wxapp'
];
for (const key of fileKeys) {
  const dec = tryDecrypt(b, Buffer.from(key));
  for (let o = 0; o < Math.min(1000, dec.length - 2); o++) {
    if ((dec[o] === 0x78 && (dec[o+1] === 0x9c || dec[o+1] === 0xda))) {
      console.log(`\nFound zlib after decrypt with key "${key}" at offset ${o}`);
      try {
        const decompressed = zlib.inflateSync(dec.slice(o));
        const text = decompressed.toString('utf8').substring(0, 300);
        console.log('Decompressed:', text);
      } catch(e) {}
    }
  }
}

